import amqp from 'amqplib';

const conn = await amqp.connect('amqp://localhost');
const ch = await conn.createChannel();

await ch.assertExchange('orders', 'topic', { durable: true });
await ch.assertQueue('orders.fulfillment', { durable: true });
await ch.bindQueue('orders.fulfillment', 'orders', 'orders.created');

// Producer: fire-and-forget, API returns immediately
ch.publish('orders', 'orders.created', Buffer.from(JSON.stringify({ orderId: 'abc123' })), { persistent: true });

// Consumer: process at controlled rate
await ch.prefetch(1);
ch.consume('orders.fulfillment', async (msg) => {
  if (!msg) return;
  await fulfillOrder(JSON.parse(msg.content.toString()));
  ch.ack(msg);
});

// Node.js amqplib — declare queue with DLX and check x-death count
const channel = await connection.createChannel();

await channel.assertExchange('dlx', 'direct', { durable: true });
await channel.assertQueue('jobs.dlq', { durable: true });
await channel.bindQueue('jobs.dlq', 'dlx', 'jobs');

await channel.assertQueue('jobs', {
  durable: true,
  arguments: {
    'x-dead-letter-exchange': 'dlx',
    'x-dead-letter-routing-key': 'jobs',
  },
});

channel.consume('jobs', (msg) => {
  const deaths = msg.properties.headers['x-death'];
  const deathCount = deaths?.[0]?.count ?? 0;

  if (deathCount >= 5) {
    // Poison message — send to permanent graveyard and ack
    channel.publish('', 'jobs.graveyard', msg.content, { persistent: true });
    channel.ack(msg);
    return;
  }

  try {
    process(msg);
    channel.ack(msg);
  } catch {
    channel.nack(msg, false, false); // requeue=false → triggers DLX
  }
});

import amqplib from 'amqplib';

const conn = await amqplib.connect('amqp://localhost');
const ch = await conn.createChannel();

await ch.prefetch(10); // per-consumer, not global

await ch.assertExchange('orders', 'topic', { durable: true });
await ch.assertQueue('order.payments', { durable: true });
await ch.bindQueue('order.payments', 'orders', 'order.*.created');

ch.consume('order.payments', (msg) => {
  if (!msg) return;
  try {
    processOrder(JSON.parse(msg.content.toString()));
    ch.ack(msg);
  } catch {
    ch.nack(msg, false, false); // dead-letter, don't requeue
  }
}, { noAck: false });

// Node.js amqplib — consistent-hash partitioned publish
const conn = await amqp.connect('amqp://localhost');
const ch = await conn.createChannel();

await ch.assertExchange('orders.partitioned', 'x-consistent-hash', { durable: true });

// Bind 4 ordered queues with equal weight
for (let i = 0; i < 4; i++) {
  await ch.assertQueue(`orders.q${i}`, { durable: true });
  await ch.bindQueue(`orders.q${i}`, 'orders.partitioned', '25'); // weight
}

// Publish: routing key = partition key → deterministic queue
const userId = '42';
ch.publish('orders.partitioned', `user:${userId}`,
  Buffer.from(JSON.stringify({ orderId: 'abc', userId })),
  { persistent: true }
);

// Consumer: prefetch=1 enforces per-queue ordering
await ch.prefetch(1);
ch.consume('orders.q0', msg => {
  processInOrder(msg);
  ch.ack(msg);
});

