import amqplib from 'amqplib';

const conn = await amqplib.connect('amqp://localhost');
const ch = await conn.createChannel();

// Priority queue: 0–10, higher value = dequeued first
await ch.assertQueue('jobs', { arguments: { 'x-max-priority': 10 } });

// Rate limiting: max 5 unacked messages in-flight per consumer
ch.prefetch(5);

// High-priority publish
ch.sendToQueue('jobs', Buffer.from(JSON.stringify({ task: 'critical' })), {
  priority: 9,
  persistent: true,
});

// Repeatable jobs via delayed exchange plugin
await ch.assertExchange('delayed', 'x-delayed-message', {
  arguments: { 'x-delayed-type': 'direct' },
});
ch.publish('delayed', 'jobs', Buffer.from(JSON.stringify({ task: 'poll' })), {
  headers: { 'x-delay': 30000 }, // re-publish inside consumer to repeat
});

